/**
 * @name RemotingSerializable decode with fastjson from network - taint path
 * @description RemotingSerializable.decode processes JSON from network - fastjson with autoType
 * @kind path-problem
 * @problem.severity error
 * @id java/rocketmq-remotingserializable-fastjson
 * @tags security
 *       external/cwe/cwe-502
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module FastjsonNetworkConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("parseObject") or
        mc.getMethod().hasName("parse")
      ) and
      mc.getMethod().getDeclaringType().hasQualifiedName("com.alibaba.fastjson", "JSON") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module FastjsonNetworkFlow = TaintTracking::Global<FastjsonNetworkConfig>;
import FastjsonNetworkFlow::PathGraph

from FastjsonNetworkFlow::PathNode source, FastjsonNetworkFlow::PathNode sink
where FastjsonNetworkFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Fastjson parse with data from $@.", source.getNode(), "remote source"

/**
 * @name Taint from network to getRocketmqHome used in shell command
 * @description Traces whether rocketmqHome property (set via updateBrokerConfig) reaches 
 *              the shell command builder used in FilterServerManager.buildStartCommand
 * @kind path-problem  
 * @problem.severity error
 * @id java/rocketmq-rocketmqhome-to-exec
 * @tags security
 *       external/cwe/cwe-094
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module RocketmqHomeExecConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Source: any call to getRocketmqHome() - this is network-settable via updateBrokerConfig
    exists(MethodCall mc |
      mc.getMethod().hasName("getRocketmqHome") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: Runtime.exec() argument
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Runtime") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Or callShell argument
    exists(MethodCall mc |
      mc.getMethod().hasName("callShell") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.rocketmq.broker.filtersrv", "FilterServerUtil") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module RocketmqHomeExecFlow = TaintTracking::Global<RocketmqHomeExecConfig>;
import RocketmqHomeExecFlow::PathGraph

from RocketmqHomeExecFlow::PathNode source, RocketmqHomeExecFlow::PathNode sink
where RocketmqHomeExecFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "getRocketmqHome() value reaches shell/exec in $@.", source.getNode(), "getRocketmqHome()"
